INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8962ebe6-6932-4c53-a3b6-1871ab1b5d47',
  '00000000-0000-0000-0000-000000000001',
  $escape$Optimism — Understanding Post-Merge Ethereum Accounts and Transactions$escape$,
  $escape$On Optimism, Ethereum accounts are abstracted using the Ethereum Provider API. Transactions are executed using the `eth_sendTransaction` method, which takes a transaction object as an argument. The transaction object includes properties such as `from`, `to`, `value`, `gas`, and `gasPrice`. Post-merge, Optimism utilizes a Proof of Stake (PoS) consensus algorithm, ensuring energy efficiency and security. The `eth_getBlockByNumber` method can be used to retrieve block structure information, including the block number, hash, and transactions.$escape$,
  $escape$const { ethers } = require('ethers');
const provider = new ethers.providers.JsonRpcProvider('https://mainnet.optimism.io');
const tx = {
  from: '0x...',
  to: '0x...',
  value: ethers.utils.parseEther('1.0'),
  gas: '20000',
  gasPrice: ethers.utils.parseUnits('20.0', 'gwei')
};
provider.sendTransaction(tx).then((txHash) => console.log(txHash));$escape$,
  $escape$javascript$escape$,
