INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '404db178-cc82-4697-a7d0-a80fdf5addc4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Optimism Rollups: Fraud Proofs, Challenge Period, and Withdrawal Delay$escape$,
  $escape$When a user submits a transaction on Optimism, it's initially considered valid. However, this creates a problem known as the 'nothing-at-stake' problem. To mitigate this, Optimism uses a two-phase verification process called Optimistic Rollups. The first phase assumes the transaction is valid, and the second phase, called the challenge period, allows anyone to challenge the transaction. If a challenge occurs, the transaction is reverted. To prevent this, Optimism introduces a withdrawal delay, which temporarily locks funds. This ensures the integrity of the rollup and prevents cheating.$escape$,
  NULL,
  NULL,
